SELECT SUM(experience) AS total_experience
FROM portfolio_manager
WHERE description = 'Portfolio manager with 10 years of experience';

SELECT COUNT(transaction_id) AS transaction_count
FROM instrument_transaction
WHERE instrument_id = 0;

SELECT MAX(result) AS max_stress_test_result
FROM stress_test
WHERE risk_model_id = 1 AND date >= '2020-01-01';

SELECT stress_test_id, risk_model_id, date, scenario
FROM stress_test
WHERE scenario = 'Market crash';
